import redis

def run_lua_script(script_code, keys, args):
    """
    Connects to Redis, executes a Lua script, and returns the result.

    Args:
        script_code (str): The Lua script code to execute.
        keys (list): A list of keys to pass to the Lua script.
        args (list): A list of arguments to pass to the Lua script.

    Returns:
        The result of the Lua script execution.
    """
    try:
        # Connect to Redis
        # You might want to configure host, port, db, password based on your setup
        r = redis.Redis(host='localhost', port=6379, db=0)
        r.ping()
        print("Connected to Redis successfully!")

        # Execute the Lua script
        result = r.eval(script_code, len(keys), *keys, *args)
        return result

    except redis.exceptions.ConnectionError as e:
        print(f"Could not connect to Redis: {e}")
        return None
    except Exception as e:
        print(f"An error occurred: {e}")
        return None

